import client from './client'

export default {
    getAllPictures(pageNum) {
        return client.get('/alllist', {
            params: {
                page_num: pageNum || 1
            }
        })
    },
    refreshAllPictures() {
        return client.get('/refresh')
    },
    deletePicture(id) {
        return client.delete('/' + id)
    },
    recoverPicture(id) {
        return client.get('/recover/' + id)
    }
}
