import api from '@/api/service'

export default {
    name: 'PictureList',
    data() {
        return {
            pageNum: Number(this.$route.query.pageNum) || 1,
            pictureInfos: []
        }
    },
    async created() {
        await this.doGetPicturesApi()
    },
    methods: {
        async doGetPicturesApi() {
            try {
                this.pictureInfos = await api.getAllPictures(this.pageNum)
            } catch (error) {
                console.log(error)
            }
        },
        async doRefreshPicturesApi() {
            try {
                await api.refreshAllPictures()
            } catch (error) {
                console.log(error)
            }
        },
        async doDeletePictureApi(id) {
            try {
                await api.deletePicture(id)
            } catch (error) {
                console.log(error)
            }
        },
        async doRecoverPictureApi(id) {
            try {
                await api.recoverPicture(id)
            } catch (error) {
                console.log(error)
            }
        },
        onBtnPrevPageClick() {
            this.$router.replace({
                path: '/pictures',
                query: {
                    pageNum: this.pageNum - 1
                }
            })
        },
        onBtnNextPageClick() {
            this.$router.replace({
                path: '/pictures',
                query: {
                    pageNum: this.pageNum + 1
                }
            })
        },
        async onBtnRefreshToAppClick() {
            await this.doRefreshPicturesApi()
        },
        async onBtnDeletePictureClick(pictureInfo) {
            await this.doDeletePictureApi(pictureInfo.id)
            pictureInfo.deleteStatus = 0
        },
        async onBtnRecoverPictureClick(pictureInfo) {
            await this.doRecoverPictureApi(pictureInfo.id)
            pictureInfo.deleteStatus = 1
        }
    }
}
