import axios from 'axios'

function isResponseOk(response) {
    return response.status >= 200 && response.status < 300 && response.data && response.data.status >= 200 && response.data.status < 300
}

function convertResponseToError(response, detail) {
    let status = response.status
    let code = -1
    let message = '网络请求错误，请重试'
    if (response.data && response.data.status) {
        code = response.data.status
        message = response.data.msg
    }
    return {
        status,
        code,
        message,
        detail
    }
}

const instance = axios.create({
    baseURL: process.env.VUE_APP_API_BASE_URL,
    headers: {
        'Cache-Control': 'no-cache'
    }
})

instance.interceptors.response.use(response => {
    if (isResponseOk(response)) {
        if (process.env.VUE_APP_LOG_ENABLED === 'true') {
            console.info(response)
        }
        return response.data.data
    } else {
        const error = convertResponseToError(response, response)
        if (process.env.VUE_APP_LOG_ENABLED === 'true') {
            console.error({
                tag: 'http-response',
                error
            })
        }
        throw error
    }
}, error => {
    error = convertResponseToError(error.response, error)
    if (process.env.VUE_APP_LOG_ENABLED === 'true') {
        console.error({
            tag: 'http-response',
            error
        })
    }
    return Promise.reject(error)
})

export default instance
